export interface Flashcard {
  id: string;
  subject: string;
  topic: string;
  front: string;
  back: string;
}

export const flashcards: Flashcard[] = [
  // DEUTSCH A — Areas of Exploration
  { id: "fc-de1", subject: "deutsch", topic: "Leser, Autoren und Texte", front: "Was untersucht 'Leser, Autoren und Texte'?", back: "Wie und warum Texte Bedeutung erzeugen. Beziehung zwischen Autor, Text und Leser. Textarten, Stilmittel, Publikum und Zweck." },
  { id: "fc-de2", subject: "deutsch", topic: "Zeit und Raum", front: "Was untersucht 'Zeit und Raum'?", back: "Wie kulturelle, historische und soziale Kontexte die Textproduktion und -rezeption beeinflussen. Texte als Produkte ihrer Zeit." },
  { id: "fc-de3", subject: "deutsch", topic: "Intertextualität", front: "Was ist Intertextualität?", back: "Verbindungen zwischen Texten — wie sie aufeinander verweisen, sich ergänzen, parodieren oder widersprechen. Vergleich von Werten und Einstellungen." },
  // Schlüsselkonzepte
  { id: "fc-de4", subject: "deutsch", topic: "Schlüsselkonzepte", front: "Nenne die 7 Schlüsselkonzepte.", back: "Identität, Kultur, Kreativität, Kommunikation, Perspektive, Transformation, Repräsentation. Sie durchziehen den gesamten Kurs." },
  { id: "fc-de5", subject: "deutsch", topic: "Schlüsselkonzepte", front: "Was bedeutet 'Repräsentation' als Konzept?", back: "Wie Sprache und Texte die Welt darstellen. Welche Realitäten werden gezeigt, welche ausgeblendet? Wessen Stimme wird gehört?" },
  // Stilmittel & Textanalyse
  { id: "fc-de6", subject: "deutsch", topic: "Stilmittel & Textanalyse", front: "Was ist eine Metapher?", back: "Ein sprachliches Bild — ein Wort wird in übertragener Bedeutung verwendet. Z.B. 'Wüstenschiff' für Kamel, 'Meer der Tränen'." },
  { id: "fc-de7", subject: "deutsch", topic: "Stilmittel & Textanalyse", front: "Was ist ein Oxymoron?", back: "Verbindung zweier sich widersprechender Begriffe. Z.B. 'bittersüß', 'alter Knabe', 'offenes Geheimnis'. Erzeugt Spannung." },
  { id: "fc-de8", subject: "deutsch", topic: "Stilmittel & Textanalyse", front: "Was ist die PEE-Methode?", back: "Point (These), Evidence (Textbeleg/Zitat), Explanation (Wirkung erklären). Grundstruktur jeder Textanalyse im IB." },
  { id: "fc-de9", subject: "deutsch", topic: "Stilmittel & Textanalyse", front: "Was ist Ironie?", back: "Das Gegenteil des Gesagten ist gemeint. Wahre Aussage ergibt sich aus Kontext. Kann humorvoll, kritisch oder sarkastisch wirken." },
  { id: "fc-de10", subject: "deutsch", topic: "Stilmittel & Textanalyse", front: "Was ist eine Alliteration?", back: "Wiederholung des gleichen Anfangslauts in aufeinanderfolgenden Wörtern. Z.B. 'Milch macht müde Männer munter'. Rhythmische Wirkung." },
  { id: "fc-de11", subject: "deutsch", topic: "Stilmittel & Textanalyse", front: "Was ist ein Parallelismus?", back: "Wiederholung der gleichen syntaktischen Struktur. Z.B. 'Ich kam, ich sah, ich siegte.' Betont, verstärkt Rhythmus." },
  { id: "fc-de12", subject: "deutsch", topic: "Stilmittel & Textanalyse", front: "Was ist eine Anapher?", back: "Wiederholung eines Wortes/einer Wortgruppe am Satzanfang. Z.B. 'Er ging. Er lief. Er rannte.' Steigernde Wirkung." },
  { id: "fc-de13", subject: "deutsch", topic: "Stilmittel & Textanalyse", front: "Was ist eine Hyperbel?", back: "Starke Übertreibung. Z.B. 'todmüde', 'blitzschnell', 'ein Meer von Tränen'. Betont oder dramatisiert." },
  { id: "fc-de14", subject: "deutsch", topic: "Stilmittel & Textanalyse", front: "Was ist eine Personifikation?", back: "Vermenschlichung von Gegenständen/Abstraktem. Z.B. 'Die Sonne lacht', 'Der Wind flüstert'. Macht Texte lebendig." },
  // Gattungen
  { id: "fc-de15", subject: "deutsch", topic: "Literarische Gattungen", front: "Nenne die drei Hauptgattungen.", back: "Epik (erzählende Texte: Roman, Novelle, Kurzgeschichte), Lyrik (Gedichte), Dramatik (Theaterstücke: Tragödie, Komödie)." },
  { id: "fc-de16", subject: "deutsch", topic: "Literarische Gattungen", front: "Was ist eine Erzählperspektive?", back: "Ich-Erzähler (subjektiv, eingeschränkt), auktorialer Erzähler (allwissend), personaler Erzähler (aus Sicht einer Figur, 3. Person)." },
  // Sprache
  { id: "fc-de17", subject: "deutsch", topic: "Sprache und Identität", front: "Was ist Code-Switching?", back: "Wechsel zwischen Sprachen oder Sprachvarietäten je nach Situation. Z.B. Dialekt zu Hause, Standarddeutsch in der Schule." },
  { id: "fc-de18", subject: "deutsch", topic: "Sprache und Identität", front: "Was sind Sprachvarietäten?", back: "Dialekt (regional), Soziolekt (soziale Gruppe), Fachsprache (beruflich), Jugendsprache, Standardsprache. Sprache spiegelt Identität." },
  // Assessment
  { id: "fc-de19", subject: "deutsch", topic: "Paper 1: Textanalyse", front: "Was ist Paper 1 HL?", back: "Analyse von 2 unbekannten nicht-literarischen Texten anhand einer Leitfrage. 2 Stunden 15 Min. 35% der Note." },
  { id: "fc-de20", subject: "deutsch", topic: "Paper 2: Vergleichender Aufsatz", front: "Was ist Paper 2?", back: "Vergleichender Aufsatz über mindestens 2 literarische Werke. Eine von 4 Fragen beantworten. 1 Std 45 Min. 25% der Note." },
  { id: "fc-de21", subject: "deutsch", topic: "Individual Oral (IO)", front: "Aufbau des Individual Oral?", back: "10 Min Präsentation + 5 Min Fragen. Ein literarischer + ein nicht-literarischer Text, verbunden durch eine globale Fragestellung. 30% der Note." },
  { id: "fc-de22", subject: "deutsch", topic: "HL Essay", front: "Was ist der HL Essay?", back: "1200-1500 Wörter analytischer Essay über ein Werk oder Textkorpus. Eigene Fragestellung entwickeln. 20% der Note. Wird extern bewertet." },
  { id: "fc-de23", subject: "deutsch", topic: "Individual Oral (IO)", front: "Was sind IO-Bewertungskriterien?", back: "A: Wissen und Verständnis (10). B: Analyse und Bewertung (10). C: Fokus und Organisation (10). D: Sprache (10). Gesamt: 40 Punkte." },
  { id: "fc-de24", subject: "deutsch", topic: "Textanforderungen HL", front: "Wie viele Werke werden im HL-Kurs studiert?", back: "6 Werke gesamt. Mindestens 2 in der Originalsprache (Deutsch), mindestens 2 in Übersetzung. Verschiedene Gattungen und Epochen." },

  // BUSINESS MANAGEMENT — Unit 1: Introduction
  { id: "fc-bm1", subject: "business", topic: "1.1 What is a Business?", front: "What are the four sectors of the economy?", back: "Primary (extraction), Secondary (manufacturing), Tertiary (services), Quaternary (knowledge/IT). Most developed economies are dominated by tertiary sector." },
  { id: "fc-bm2", subject: "business", topic: "1.2 Types of Business Entities", front: "What is a sole trader vs a partnership?", back: "Sole trader: one owner, unlimited liability, keeps all profit. Partnership: 2+ owners, shared liability (usually unlimited), shared profits via deed of partnership." },
  { id: "fc-bm3", subject: "business", topic: "1.2 Types of Business Entities", front: "What is the difference between a private and public limited company?", back: "Private (Ltd): shares sold privately, not on stock exchange. Public (PLC): shares traded on stock exchange, can raise more capital but risk hostile takeovers." },
  { id: "fc-bm4", subject: "business", topic: "1.3 Business Objectives", front: "What makes an objective SMART?", back: "Specific, Measurable, Achievable, Relevant, Time-bound. SMART objectives provide clear targets and allow progress to be evaluated." },
  { id: "fc-bm5", subject: "business", topic: "1.4 Stakeholders", front: "Stakeholders vs Shareholders?", back: "Shareholders own shares in the company. Stakeholders = anyone affected by the business: employees, customers, suppliers, community, government, shareholders." },
  { id: "fc-bm6", subject: "business", topic: "1.5 Growth and Evolution", front: "What are economies of scale?", back: "Cost advantages from increasing production. Types: purchasing, technical, financial, marketing, managerial. Average cost per unit falls as output increases." },
  { id: "fc-bm7", subject: "business", topic: "1.5 Growth and Evolution", front: "What is the difference between internal and external growth?", back: "Internal (organic): expanding from within (new products, more staff). External (inorganic): mergers, acquisitions, joint ventures, strategic alliances. External is faster but riskier." },
  { id: "fc-bm8", subject: "business", topic: "1.6 Multinational Companies", front: "What are advantages and disadvantages of MNCs for host countries?", back: "Advantages: jobs, tax revenue, technology transfer, infrastructure. Disadvantages: profit repatriation, cultural erosion, environmental damage, exploitation of workers." },
  // BUSINESS MANAGEMENT — Unit 2: HRM
  { id: "fc-bm9", subject: "business", topic: "2.3 Leadership", front: "Compare autocratic, democratic and laissez-faire leadership.", back: "Autocratic: leader decides alone, fast but low morale. Democratic: team involved, higher morale but slower. Laissez-faire: hands-off, creative freedom but risk of lack of direction." },
  { id: "fc-bm10", subject: "business", topic: "2.4 Motivation", front: "What is Maslow's Hierarchy of Needs?", back: "5 levels: 1. Physiological 2. Safety 3. Social/belonging 4. Esteem 5. Self-actualization. Lower needs must be met before higher ones motivate." },
  { id: "fc-bm11", subject: "business", topic: "2.4 Motivation", front: "What is Herzberg's Two-Factor Theory?", back: "Motivators (achievement, recognition, responsibility) → satisfaction. Hygiene factors (salary, conditions, policies) → prevent dissatisfaction but don't motivate." },
  { id: "fc-bm12", subject: "business", topic: "2.4 Motivation", front: "What is Pink's Drive Theory?", back: "Three intrinsic motivators: Autonomy (control over work), Mastery (desire to improve), Purpose (meaningful work). Financial incentives can actually reduce intrinsic motivation." },
  { id: "fc-bm13", subject: "business", topic: "2.5 Organizational Culture (HL)", front: "What are Handy's four types of organizational culture?", back: "Power: central figure, few rules. Role: bureaucratic, clear hierarchy. Task: team-based, project-focused. Person: individuals are central, loose structure (e.g., law firms)." },
  // BUSINESS MANAGEMENT — Unit 3: Finance
  { id: "fc-bm14", subject: "business", topic: "3.3 Costs and Revenues", front: "What is the difference between fixed and variable costs?", back: "Fixed: don't change with output (rent, salaries). Variable: change with output (raw materials, packaging). Total cost = fixed + variable." },
  { id: "fc-bm15", subject: "business", topic: "3.5 Profitability Ratios", front: "What is the Gross Profit Margin formula?", back: "GPM = (Gross Profit / Revenue) × 100%. Shows efficiency of production. Gross Profit = Revenue - COGS." },
  { id: "fc-bm16", subject: "business", topic: "3.5 Profitability Ratios", front: "What does the current ratio measure?", back: "Current ratio = Current Assets / Current Liabilities. Measures short-term liquidity. Ideal: 1.5-2.0. Below 1 = may struggle to pay debts." },
  { id: "fc-bm17", subject: "business", topic: "3.7 Cash Flow", front: "What is the difference between profit and cash flow?", back: "Profit = revenue - costs (over a period). Cash flow = actual money in and out. A profitable business can still run out of cash (e.g., slow-paying customers)." },
  { id: "fc-bm18", subject: "business", topic: "3.8 Investment Appraisal", front: "Compare payback period, ARR, and NPV.", back: "Payback: time to recover investment (simple but ignores time value). ARR: average annual return as % (easy to compare). NPV: discounts future cash flows (most accurate, HL)." },
  // BUSINESS MANAGEMENT — Unit 4: Marketing
  { id: "fc-bm19", subject: "business", topic: "4.2 Marketing Planning", front: "What is market segmentation?", back: "Dividing a market into groups with similar needs. Bases: demographic (age, gender), geographic, psychographic (lifestyle), behavioral (usage). Allows targeted marketing." },
  { id: "fc-bm20", subject: "business", topic: "4.5 The Seven Ps", front: "What are the 7Ps of the marketing mix?", back: "Product, Price, Place, Promotion, People, Process, Physical Evidence. The extra 3Ps are especially important for service businesses." },
  { id: "fc-bm21", subject: "business", topic: "4.5 The Seven Ps", front: "What is the product life cycle (PLC)?", back: "Stages: Introduction (low sales, high costs), Growth (rising sales), Maturity (peak sales, competition), Decline (falling sales). Extension strategies can prolong maturity." },
  { id: "fc-bm22", subject: "business", topic: "4.5 The Seven Ps", front: "What is the Boston Consulting Group (BCG) matrix?", back: "Classifies products by market share and market growth: Stars (high/high), Cash Cows (high/low), Question Marks (low/high), Dogs (low/low). Guides portfolio strategy." },
  // BUSINESS MANAGEMENT — Unit 5: Operations
  { id: "fc-bm23", subject: "business", topic: "5.2 Operations Methods", front: "Compare job, batch, and mass production.", back: "Job: one-off, custom (expensive). Batch: groups of identical products (flexible). Mass/flow: continuous large-scale (low unit cost). Choice depends on demand and product type." },
  { id: "fc-bm24", subject: "business", topic: "5.5 Break-Even Analysis", front: "What is the break-even formula?", back: "Break-even quantity = Fixed Costs / (Selling Price - Variable Cost per unit). At break-even: Total Revenue = Total Costs, profit = 0." },
  { id: "fc-bm25", subject: "business", topic: "5.5 Break-Even Analysis", front: "What is margin of safety?", back: "Margin of safety = Actual output - Break-even output. Shows how far sales can drop before the business makes a loss." },
  { id: "fc-bm26", subject: "business", topic: "5.3 Lean Production (HL)", front: "What is JIT (Just-in-Time)?", back: "Stock arrives exactly when needed, reducing storage costs and waste. Requires reliable suppliers. Risk: no buffer stock if supply chain disrupted." },
  // BUSINESS MANAGEMENT — Toolkit
  { id: "fc-bm27", subject: "business", topic: "BM Toolkit", front: "What is a SWOT analysis?", back: "Strengths (internal +), Weaknesses (internal -), Opportunities (external +), Threats (external -). Used for strategic planning and decision-making." },
  { id: "fc-bm28", subject: "business", topic: "BM Toolkit", front: "What is the Ansoff Matrix?", back: "4 growth strategies: Market Penetration (existing product/market), Market Development (existing product/new market), Product Development (new product/existing market), Diversification (new/new — riskiest)." },
  { id: "fc-bm29", subject: "business", topic: "BM Toolkit", front: "What is STEEPLE analysis?", back: "Social, Technological, Economic, Environmental, Political, Legal, Ethical factors. Analyses the external macro-environment affecting a business." },
  { id: "fc-bm30", subject: "business", topic: "BM Toolkit", front: "What is Porter's Five Forces? (HL)", back: "1. Threat of new entrants 2. Bargaining power of suppliers 3. Bargaining power of buyers 4. Threat of substitutes 5. Industry rivalry. Determines industry attractiveness." },

  // DESIGN TECHNOLOGY — Topic 1: Human Factors
  { id: "fc-dt1", subject: "design-tech", topic: "1.1 Ergonomics", front: "What is the difference between ergonomics and anthropometrics?", back: "Ergonomics: designing for comfort and efficiency in human use. Anthropometrics: using body measurement data (heights, reaches, grip sizes) to inform design dimensions." },
  { id: "fc-dt2", subject: "design-tech", topic: "1.1 Ergonomics", front: "What is a percentile range in design?", back: "Products typically designed for 5th-95th percentile (90% of users). Designing for extremes would make products unusable for most. Safety features should accommodate 99th percentile." },
  { id: "fc-dt3", subject: "design-tech", topic: "1.2 Psychological Factors", front: "What is a mental model in design?", back: "A user's internal understanding of how a product works. Good design matches user expectations. If a mental model is wrong, the product feels confusing." },
  { id: "fc-dt4", subject: "design-tech", topic: "1.3 Physiological Factors", front: "What is RSI and how can design prevent it?", back: "Repetitive Strain Injury: caused by repeated motions. Prevention: ergonomic keyboards, adjustable chairs, varied work positions, regular breaks." },
  // DT — Topic 2: Sustainability
  { id: "fc-dt5", subject: "design-tech", topic: "2.2 Waste Mitigation", front: "What is planned obsolescence?", back: "Deliberately designing products with a limited lifespan to encourage repeat purchases. Types: technological (outdated features), psychological (fashion changes), material (weak components)." },
  { id: "fc-dt6", subject: "design-tech", topic: "2.5 Green Design", front: "What is cradle-to-cradle design?", back: "Products designed so all materials can be fully recycled or composted at end of life — no waste. Biological nutrients return to nature, technical nutrients are recycled infinitely." },
  { id: "fc-dt7", subject: "design-tech", topic: "2.5 Green Design", front: "What is a life-cycle assessment (LCA)?", back: "Evaluates environmental impact at every stage: raw material extraction → manufacturing → distribution → use → disposal. Identifies where to reduce impact." },
  { id: "fc-dt8", subject: "design-tech", topic: "2.3 Energy", front: "What is embodied energy?", back: "The total energy used to produce a product — from raw material extraction through manufacturing, transport, and assembly. Higher embodied energy = larger environmental footprint." },
  // DT — Topic 3: Modelling
  { id: "fc-dt9", subject: "design-tech", topic: "3.1 Modelling", front: "What is the difference between orthographic and isometric drawing?", back: "Orthographic: 2D technical views (front, side, top/plan) with exact dimensions. Isometric: 3D representation at 30° angles, shows form but not true dimensions." },
  { id: "fc-dt10", subject: "design-tech", topic: "3.2 Digital Modelling", front: "What is rapid prototyping?", back: "Quick fabrication of physical models using 3D printing (FDM, SLA, SLS), laser cutting, or CNC machining. Allows fast design iteration and testing." },
  // DT — Topic 4: Materials
  { id: "fc-dt11", subject: "design-tech", topic: "4.1 Material Properties", front: "Name 5 key mechanical properties of materials.", back: "Hardness (scratch resistance), Toughness (absorbs energy without fracturing), Strength (resists force), Elasticity (returns to shape), Ductility (drawn into wire)." },
  { id: "fc-dt12", subject: "design-tech", topic: "4.2 Materials", front: "Thermoplastic vs Thermoset?", back: "Thermoplastics: can be reheated and reshaped (PET, ABS, PP). Thermosets: permanently harden through curing, cannot be remelted (epoxy, melamine, polyester resin)." },
  { id: "fc-dt13", subject: "design-tech", topic: "4.2 Materials", front: "What is a composite material?", back: "Two or more materials combined to get superior properties. Examples: carbon fibre (carbon + resin), GRP/fibreglass (glass + polyester), plywood (wood veneers + glue). Strong and lightweight." },
  { id: "fc-dt14", subject: "design-tech", topic: "4.2 Materials", front: "What is the difference between ferrous and non-ferrous metals?", back: "Ferrous: contain iron, magnetic, prone to rust (steel, cast iron). Non-ferrous: no iron, non-magnetic, corrosion-resistant (aluminium, copper, brass, titanium)." },
  { id: "fc-dt15", subject: "design-tech", topic: "4.3 Scale of Production", front: "Compare one-off, batch, and mass production.", back: "One-off: single unique product (expensive, custom). Batch: set quantities of identical items (flexible). Mass: continuous high-volume (low unit cost, high setup cost)." },
  // DT — Topic 5: Innovation
  { id: "fc-dt16", subject: "design-tech", topic: "5.1 Innovation", front: "What is the difference between invention and innovation?", back: "Invention: creating something entirely new. Innovation: improving or applying existing ideas commercially. Innovation turns inventions into marketable products." },
  { id: "fc-dt17", subject: "design-tech", topic: "5.1 Innovation", front: "What is market-pull vs technology-push?", back: "Market-pull: consumer demand drives product development. Technology-push: new technology creates products consumers didn't know they needed (e.g., smartphones)." },
  { id: "fc-dt18", subject: "design-tech", topic: "5.4 Rogers' Diffusion", front: "What are Rogers' adopter categories?", back: "Innovators (2.5%), Early Adopters (13.5%), Early Majority (34%), Late Majority (34%), Laggards (16%). Describes how new products spread through populations." },
  { id: "fc-dt19", subject: "design-tech", topic: "5.3 Product Life Cycle", front: "What are extension strategies?", back: "Methods to extend a product's maturity phase: new markets, new packaging, price changes, added features, rebranding, new uses. Delays the decline stage." },
  // DT — Topic 6: Classic Design
  { id: "fc-dt20", subject: "design-tech", topic: "6. Classic Design", front: "What characterized the Bauhaus movement?", back: "Founded 1919 in Weimar by Gropius. 'Form follows function.' Minimalism, geometric shapes, industrial materials. United art, craft, and technology. Closed 1933 by Nazis." },
  { id: "fc-dt21", subject: "design-tech", topic: "6. Classic Design", front: "What is Memphis Design?", back: "1980s Italian movement led by Ettore Sottsass. Bold colours, geometric shapes, unconventional materials. Rejected minimalism — playful, postmodern, anti-functional aesthetic." },
  // DT — HL Extensions
  { id: "fc-dt22", subject: "design-tech", topic: "7. User-Centred Design (HL)", front: "What are the 5 usability goals?", back: "Effectiveness (can they do it?), Efficiency (how quickly?), Satisfaction (do they enjoy it?), Learnability (easy to learn?), Memorability (easy to remember?). Plus error prevention." },
  { id: "fc-dt23", subject: "design-tech", topic: "7. User-Centred Design (HL)", front: "What are Norman's three levels of design?", back: "Visceral: immediate emotional reaction (appearance). Behavioural: pleasure of use (function, usability). Reflective: self-image and meaning (status, memories)." },
  { id: "fc-dt24", subject: "design-tech", topic: "8. Sustainability (HL)", front: "What is the triple bottom line?", back: "People, Planet, Profit. Businesses should measure success not just financially but also by social and environmental impact." },
  { id: "fc-dt25", subject: "design-tech", topic: "8. Sustainability (HL)", front: "What is biomimicry?", back: "Design inspired by nature's solutions. Examples: Velcro (burrs), bullet train nose (kingfisher beak), building ventilation (termite mounds)." },
  { id: "fc-dt26", subject: "design-tech", topic: "10. Commercial Production (HL)", front: "What is TQM (Total Quality Management)?", back: "A management philosophy where every employee is responsible for quality. Continuous improvement, customer focus, zero defects as a goal. Prevents rather than detects defects." },
  { id: "fc-dt27", subject: "design-tech", topic: "10. Commercial Production (HL)", front: "Compare JIT and JIC.", back: "JIT (Just-in-Time): stock arrives when needed, low storage costs, risk if supply fails. JIC (Just-in-Case): buffer stock held, higher storage costs, but supply guaranteed." },

  // ENGLISH A L&L — Areas of Exploration
  { id: "fc-en1", subject: "english-ll", topic: "Readers, Writers and Texts", front: "What does 'Readers, Writers and Texts' explore?", back: "How and why texts create meaning. The relationship between author, text, and reader. Text types, stylistic features, audience and purpose." },
  { id: "fc-en2", subject: "english-ll", topic: "Time and Space", front: "What does 'Time and Space' explore?", back: "How texts are shaped by their cultural, historical, and social contexts. How meaning changes when texts are read in different times/places." },
  { id: "fc-en3", subject: "english-ll", topic: "Intertextuality: Connecting Texts", front: "What does 'Intertextuality' explore?", back: "How texts dialogue with one another. How comparing texts reveals values, attitudes, and beliefs. Adaptation, genre conventions." },
  // Key Concepts
  { id: "fc-en4", subject: "english-ll", topic: "Seven Key Concepts", front: "Name the 7 key concepts.", back: "Identity, Culture, Creativity, Communication, Perspective, Transformation, Representation. They underpin the entire course." },
  { id: "fc-en5", subject: "english-ll", topic: "Seven Key Concepts", front: "How does 'Perspective' work as a concept?", back: "How texts offer and shape points of view. Whose perspective is presented? What biases exist? How does the reader's perspective affect interpretation?" },
  // Literary Devices
  { id: "fc-en6", subject: "english-ll", topic: "Literary & Rhetorical Devices", front: "What is ethos, pathos, logos?", back: "Ethos: credibility/authority. Pathos: emotional appeal. Logos: logical reasoning. Aristotle's three modes of persuasion." },
  { id: "fc-en7", subject: "english-ll", topic: "Literary & Rhetorical Devices", front: "Name 5 common literary devices.", back: "Metaphor, simile, alliteration, imagery, symbolism. Also: irony, foreshadowing, personification, hyperbole, juxtaposition." },
  { id: "fc-en8", subject: "english-ll", topic: "Literary & Rhetorical Devices", front: "What is juxtaposition?", back: "Placing two contrasting ideas, images, or characters side by side to highlight differences and create meaning." },
  { id: "fc-en9", subject: "english-ll", topic: "Literary & Rhetorical Devices", front: "What is a motif?", back: "A recurring element (image, symbol, theme, idea) throughout a text that reinforces its central themes." },
  { id: "fc-en10", subject: "english-ll", topic: "Literary & Rhetorical Devices", front: "What is dramatic irony?", back: "When the audience/reader knows something a character does not. Creates tension, suspense, or humour." },
  { id: "fc-en11", subject: "english-ll", topic: "Literary & Rhetorical Devices", front: "What is the difference between tone and mood?", back: "Tone: the author's/speaker's attitude toward the subject. Mood: the feeling/atmosphere created for the reader. Both shaped by word choice." },
  // Text Types
  { id: "fc-en12", subject: "english-ll", topic: "Text Types & Conventions", front: "What are the key features of a persuasive speech?", back: "Rhetorical questions, rule of three, emotive language, direct address ('you'), repetition, anecdotes, ethos/pathos/logos." },
  { id: "fc-en13", subject: "english-ll", topic: "Text Types & Conventions", front: "How does an editorial differ from a news article?", back: "Editorial: opinion piece, persuasive, represents newspaper's stance. News article: factual, objective, reports events. Different purpose and tone." },
  // Language Analysis
  { id: "fc-en14", subject: "english-ll", topic: "Language Analysis Skills", front: "What is register?", back: "The level of formality in language. Formal (academic, legal), informal (conversational), colloquial (slang). Determined by audience and purpose." },
  { id: "fc-en15", subject: "english-ll", topic: "Language Analysis Skills", front: "What is connotation vs denotation?", back: "Denotation: literal dictionary meaning. Connotation: associated feelings/ideas. 'Home' denotes a dwelling but connotes warmth, safety, belonging." },
  // Assessment
  { id: "fc-en16", subject: "english-ll", topic: "Paper 1: Guided Textual Analysis", front: "How should you structure Paper 1?", back: "Introduction (text type, purpose, audience, thesis) → Body (language, structure, tone analysis with evidence) → Conclusion (overall effect). Follow the guiding question." },
  { id: "fc-en17", subject: "english-ll", topic: "Paper 2: Comparative Essay", front: "What makes a strong Paper 2 thesis?", back: "A clear, arguable claim that compares/connects two works through theme, technique, or context. Must go beyond surface-level summary." },
  { id: "fc-en18", subject: "english-ll", topic: "Individual Oral (IO)", front: "What are the IO assessment criteria?", back: "A: Knowledge & understanding (10). B: Analysis & evaluation (10). C: Focus & organization (10). D: Language (10). Total: 40 marks." },
  { id: "fc-en19", subject: "english-ll", topic: "Individual Oral (IO)", front: "How is the IO structured?", back: "10 min prepared presentation + 5 min Q&A. Connect 1 literary work + 1 non-literary text through a global issue. Use 40-line extracts." },
  { id: "fc-en20", subject: "english-ll", topic: "Time and Space", front: "What is a post-colonial reading?", back: "Examining how a text represents, reflects, or challenges colonialism, power dynamics, and cultural identity. Whose story is told? Whose is silenced?" },
  { id: "fc-en21", subject: "english-ll", topic: "Text Requirements SL", front: "How many works are studied at SL?", back: "6 works. At least 2 different literary forms, 1 work in translation, at least 2 from the Prescribed Reading List, at least 3 different authors." },

  // MATH AI — Topic 1: Number and Algebra
  { id: "fc-ma1", subject: "math-ai", topic: "1.2 Arithmetic Sequences", front: "What is the formula for the nth term of an arithmetic sequence?", back: "uₙ = u₁ + (n-1)d, where u₁ is the first term and d is the common difference. Example: 3, 7, 11, 15... → u₁=3, d=4." },
  { id: "fc-ma2", subject: "math-ai", topic: "1.2 Arithmetic Sequences", front: "What is the formula for the sum of an arithmetic series?", back: "Sₙ = n/2 × (2u₁ + (n-1)d) or Sₙ = n/2 × (u₁ + uₙ). Both are in the formula booklet." },
  { id: "fc-ma3", subject: "math-ai", topic: "1.3 Geometric Sequences", front: "What is the formula for the nth term of a geometric sequence?", back: "uₙ = u₁ × rⁿ⁻¹, where r is the common ratio. Example: 2, 6, 18, 54... → u₁=2, r=3." },
  { id: "fc-ma4", subject: "math-ai", topic: "1.3 Geometric Sequences", front: "When does a geometric series converge?", back: "When |r| < 1. The sum to infinity is S∞ = u₁/(1-r). Example: r=0.5 → series converges." },
  { id: "fc-ma5", subject: "math-ai", topic: "1.4 Financial Mathematics", front: "What is the compound interest formula?", back: "FV = PV × (1 + r/100k)ᵏⁿ, where PV=present value, r=annual rate, k=compounding periods per year, n=years. In formula booklet." },
  { id: "fc-ma6", subject: "math-ai", topic: "1.5 Exponents and Logarithms", front: "What are the key log laws?", back: "log(ab) = log a + log b. log(a/b) = log a - log b. log(aⁿ) = n log a. Change of base: logₐb = ln b / ln a." },
  { id: "fc-ma7", subject: "math-ai", topic: "1.6 Approximation and Error", front: "What is the percentage error formula?", back: "Percentage error = |vA - vE|/vE × 100%, where vA = approximate value, vE = exact value." },
  // MATH AI — Topic 2: Functions
  { id: "fc-ma8", subject: "math-ai", topic: "2.1 Function Concepts", front: "What are domain and range?", back: "Domain: set of all possible input (x) values. Range: set of all possible output (y) values. Read from the graph or algebraic expression." },
  { id: "fc-ma9", subject: "math-ai", topic: "2.5 Quadratic Models", front: "What is the quadratic formula?", back: "x = (-b ± √(b²-4ac)) / 2a for ax²+bx+c=0. Discriminant Δ=b²-4ac: Δ>0 → 2 roots, Δ=0 → 1 root, Δ<0 → no real roots." },
  { id: "fc-ma10", subject: "math-ai", topic: "2.5 Quadratic Models", front: "What is the vertex form of a quadratic?", back: "f(x) = a(x-h)² + k, where (h,k) is the vertex. a>0 → opens up (minimum), a<0 → opens down (maximum)." },
  { id: "fc-ma11", subject: "math-ai", topic: "2.6 Exponential Models", front: "What is exponential growth and decay?", back: "Growth: f(x) = kaˣ where a>1. Decay: f(x) = kaˣ where 0<a<1. Horizontal asymptote y=c for f(x)=kaˣ+c." },
  { id: "fc-ma12", subject: "math-ai", topic: "2.8 Sinusoidal Models", front: "How do you find amplitude, period, and vertical shift?", back: "For f(x) = a sin(bx) + d: amplitude = |a|, period = 2π/b (or 360°/b), vertical shift = d (principal axis)." },
  { id: "fc-ma13", subject: "math-ai", topic: "2.10 Regression", front: "What does the correlation coefficient r tell you?", back: "r measures linear correlation: r=1 perfect positive, r=-1 perfect negative, r=0 no linear correlation. |r|>0.75 is generally strong." },
  // MATH AI — Topic 3: Geometry and Trigonometry
  { id: "fc-ma14", subject: "math-ai", topic: "3.1 3D Geometry", front: "What is the volume of a cone and a sphere?", back: "Cone: V = ⅓πr²h. Sphere: V = ⁴⁄₃πr³. Both in the formula booklet. Remember to identify r and h from context." },
  { id: "fc-ma15", subject: "math-ai", topic: "3.3 Sine and Cosine Rules", front: "When do you use the sine rule vs cosine rule?", back: "Sine rule: a/sinA = b/sinB — when you have angle+opposite side. Cosine rule: a² = b²+c²-2bc·cosA — when you have SAS or SSS." },
  { id: "fc-ma16", subject: "math-ai", topic: "3.3 Sine and Cosine Rules", front: "What is the area formula using sine?", back: "Area = ½ab sin C, where a and b are two sides and C is the included angle." },
  { id: "fc-ma17", subject: "math-ai", topic: "3.5 Voronoi Diagrams", front: "What is a Voronoi diagram?", back: "Divides a plane into regions based on nearest site. Each point in a region is closer to its site than any other. Edges are perpendicular bisectors between sites." },
  // MATH AI — Topic 4: Statistics and Probability
  { id: "fc-ma18", subject: "math-ai", topic: "4.3 Central Tendency", front: "How do you find the mean from a frequency table?", back: "Estimated mean = Σ(f × midpoint) / Σf. Use midpoints of class intervals for grouped data." },
  { id: "fc-ma19", subject: "math-ai", topic: "4.4 Measures of Dispersion", front: "What is standard deviation?", back: "Measures the spread of data from the mean. Small σ = data clustered near mean. Large σ = data spread out. Use GDC to calculate." },
  { id: "fc-ma20", subject: "math-ai", topic: "4.5 Correlation", front: "What is the difference between correlation and causation?", back: "Correlation: two variables move together. Causation: one directly causes the other. Correlation does NOT imply causation — always consider lurking variables." },
  { id: "fc-ma21", subject: "math-ai", topic: "4.8 Probability Diagrams", front: "What is conditional probability?", back: "P(A|B) = P(A∩B)/P(B). The probability of A given that B has occurred. Read as 'probability of A given B'." },
  { id: "fc-ma22", subject: "math-ai", topic: "4.11 Normal Distribution", front: "What are the properties of a normal distribution?", back: "Bell-shaped, symmetric about the mean. Mean = median = mode. ~68% within 1σ, ~95% within 2σ, ~99.7% within 3σ." },
  { id: "fc-ma23", subject: "math-ai", topic: "4.12 Binomial Distribution", front: "When do you use the binomial distribution?", back: "Fixed number of trials (n), two outcomes (success/failure), constant probability (p), independent trials. X ~ B(n,p). Mean = np." },
  { id: "fc-ma24", subject: "math-ai", topic: "4.13 Chi-squared Test", front: "What are the steps for a chi-squared test?", back: "1. State H₀ (no association) and H₁. 2. Calculate expected values. 3. Calculate χ² statistic. 4. Find degrees of freedom (r-1)(c-1). 5. Compare p-value to significance level." },
  { id: "fc-ma25", subject: "math-ai", topic: "4.15 t-test", front: "When do you use a t-test?", back: "To test whether a sample mean is significantly different from a known/hypothesized population mean. Requires approximately normal data. Use GDC for calculations." },
  // MATH AI — Topic 5: Calculus
  { id: "fc-ma26", subject: "math-ai", topic: "5.1 Derivatives", front: "What does a derivative represent?", back: "The instantaneous rate of change / slope of the function at a point. f'(x) > 0: increasing, f'(x) < 0: decreasing, f'(x) = 0: potential max/min." },
  { id: "fc-ma27", subject: "math-ai", topic: "5.3 Differentiation Rules", front: "What is the power rule?", back: "If f(x) = axⁿ, then f'(x) = anxⁿ⁻¹. Example: f(x) = 3x⁴ → f'(x) = 12x³." },
  { id: "fc-ma28", subject: "math-ai", topic: "5.5 Optimization", front: "How do you find a local max or min using calculus?", back: "Find where f'(x) = 0. Use second derivative test: f''(x) > 0 → local min, f''(x) < 0 → local max. Or check sign change of f'(x)." },
  { id: "fc-ma29", subject: "math-ai", topic: "5.6 Integration Basics", front: "What is integration?", back: "The reverse of differentiation (anti-derivative). ∫axⁿ dx = axⁿ⁺¹/(n+1) + C (n≠-1). The +C is the constant of integration." },
  { id: "fc-ma30", subject: "math-ai", topic: "5.7 Definite Integrals", front: "What does a definite integral represent geometrically?", back: "The area between the curve and the x-axis from x=a to x=b. Areas below x-axis are negative — use |∫| for total area." },
  { id: "fc-ma31", subject: "math-ai", topic: "5.8 Trapezoidal Rule", front: "What is the trapezoidal rule?", back: "Approximates area under a curve using trapezoids: A ≈ h/2 × (y₀ + 2y₁ + 2y₂ + ... + 2yₙ₋₁ + yₙ), where h = (b-a)/n." },

  // BIOLOGY — Theme A: Unity and Diversity
  { id: "fc-bi-A1", subject: "biology", topic: "A1.1 Water", front: "Why is water a polar molecule?", back: "Oxygen is more electronegative than hydrogen, creating an uneven charge distribution. This polarity allows hydrogen bonding between water molecules." },
  { id: "fc-bi-A2", subject: "biology", topic: "A1.1 Water", front: "What properties of water are due to hydrogen bonding?", back: "Cohesion (surface tension), adhesion (capillary action), high specific heat capacity, solvent properties, high latent heat of vaporization, ice floating (less dense than liquid water)." },
  { id: "fc-bi-A3", subject: "biology", topic: "A1.1 Water", front: "Why is water's high specific heat capacity important for life?", back: "It resists temperature changes, stabilizing aquatic environments and body temperatures. Organisms avoid rapid thermal fluctuations." },
  { id: "fc-bi-A4", subject: "biology", topic: "A1.2 Nucleic Acids", front: "What are the components of a nucleotide?", back: "A pentose sugar (deoxyribose in DNA, ribose in RNA), a phosphate group, and a nitrogenous base (A, T/U, G, or C)." },
  { id: "fc-bi-A5", subject: "biology", topic: "A1.2 Nucleic Acids", front: "How does DNA differ from RNA?", back: "DNA: double-stranded, deoxyribose sugar, bases A-T-G-C. RNA: single-stranded, ribose sugar, bases A-U-G-C." },
  { id: "fc-bi-A6", subject: "biology", topic: "A1.2 Nucleic Acids", front: "What is complementary base pairing?", back: "A pairs with T (2 H-bonds) and G pairs with C (3 H-bonds) in DNA. In RNA, A pairs with U." },
  { id: "fc-bi-A7", subject: "biology", topic: "A2.2 Cell Structure", front: "What are the key differences between prokaryotic and eukaryotic cells?", back: "Prokaryotes: no nucleus, no membrane-bound organelles, circular DNA, 70S ribosomes, smaller. Eukaryotes: nucleus, membrane-bound organelles, linear DNA, 80S ribosomes, larger." },
  { id: "fc-bi-A8", subject: "biology", topic: "A2.2 Cell Structure", front: "What is the function of the rough endoplasmic reticulum?", back: "Protein synthesis and transport. Ribosomes on its surface synthesize proteins that are folded and transported in vesicles to the Golgi apparatus." },
  { id: "fc-bi-A9", subject: "biology", topic: "A2.2 Cell Structure", front: "What are the differences between plant and animal cells?", back: "Plant cells have: cell wall, chloroplasts, large central vacuole, plasmodesmata. Animal cells have: centrioles, small vacuoles, no cell wall." },
  { id: "fc-bi-A10", subject: "biology", topic: "A3.1 Diversity of Organisms", front: "What is binomial nomenclature?", back: "A two-part naming system: Genus + species (e.g., Homo sapiens). Genus is capitalized, species is lowercase, both italicized." },
  { id: "fc-bi-A11", subject: "biology", topic: "A3.1 Diversity of Organisms", front: "What is a karyotype?", back: "A display of all chromosomes of an organism, arranged in homologous pairs by size. Used to detect chromosomal abnormalities (e.g., Down syndrome = trisomy 21)." },
  { id: "fc-bi-A12", subject: "biology", topic: "A4.1 Evolution and Speciation", front: "What evidence supports evolution?", back: "Fossil record, homologous structures (comparative anatomy), DNA/molecular evidence, biogeography, observed natural selection (e.g., antibiotic resistance)." },
  { id: "fc-bi-A13", subject: "biology", topic: "A4.1 Evolution and Speciation", front: "What is natural selection?", back: "Individuals with heritable traits better suited to the environment survive and reproduce more. Over time, advantageous alleles increase in frequency in the population." },
  { id: "fc-bi-A14", subject: "biology", topic: "A4.1 Evolution and Speciation", front: "What is the difference between allopatric and sympatric speciation?", back: "Allopatric: geographic isolation separates populations. Sympatric: new species arise in the same area (e.g., polyploidy in plants). Both lead to reproductive isolation." },
  { id: "fc-bi-A15", subject: "biology", topic: "A4.2 Conservation of Biodiversity", front: "Why is biodiversity important?", back: "Ecosystem stability, genetic resources for medicine/agriculture, ecosystem services (pollination, water purification), ethical/aesthetic value." },

  // BIOLOGY — Theme B: Form and Function
  { id: "fc-bi-B1", subject: "biology", topic: "B1.1 Carbohydrates and Lipids", front: "What are condensation and hydrolysis reactions?", back: "Condensation: joins monomers by removing water (builds polymers). Hydrolysis: breaks polymers by adding water (releases monomers). Opposite reactions." },
  { id: "fc-bi-B2", subject: "biology", topic: "B1.1 Carbohydrates and Lipids", front: "Compare the structures of starch, glycogen and cellulose.", back: "All glucose polymers. Starch (amylose + amylopectin): energy storage in plants. Glycogen: energy storage in animals, highly branched. Cellulose: structural, β-glucose, straight chains with H-bonds." },
  { id: "fc-bi-B3", subject: "biology", topic: "B1.1 Carbohydrates and Lipids", front: "What is the structure of a phospholipid?", back: "Glycerol + 2 fatty acids + 1 phosphate group. Hydrophilic head (phosphate) and hydrophobic tails (fatty acids). Forms the bilayer of cell membranes." },
  { id: "fc-bi-B4", subject: "biology", topic: "B1.1 Carbohydrates and Lipids", front: "What is the difference between saturated and unsaturated fatty acids?", back: "Saturated: no C=C double bonds, straight chains, solid at room temp. Unsaturated: one or more C=C bonds, kinked chains, liquid at room temp." },
  { id: "fc-bi-B5", subject: "biology", topic: "B1.2 Proteins", front: "What determines protein shape and function?", back: "The amino acid sequence (primary structure) determines folding into secondary (α-helix, β-sheet), tertiary (3D shape via R-group interactions), and quaternary structure (multiple polypeptides)." },
  { id: "fc-bi-B6", subject: "biology", topic: "B1.2 Proteins", front: "What is protein denaturation?", back: "Loss of 3D structure due to breaking of hydrogen and ionic bonds by heat or extreme pH. The active site changes shape and the protein loses function. Irreversible in most cases." },
  { id: "fc-bi-B7", subject: "biology", topic: "B2.1 Membranes and Membrane Transport", front: "Describe the fluid mosaic model.", back: "Phospholipid bilayer with proteins (integral and peripheral), cholesterol, and glycoproteins. 'Fluid' = components move laterally. 'Mosaic' = diverse protein pattern." },
  { id: "fc-bi-B8", subject: "biology", topic: "B2.1 Membranes and Membrane Transport", front: "Compare simple diffusion, facilitated diffusion, and active transport.", back: "Simple diffusion: small/nonpolar molecules, no energy, down gradient. Facilitated: large/polar molecules via channel/carrier proteins, no energy, down gradient. Active transport: against gradient, requires ATP and carrier proteins." },
  { id: "fc-bi-B9", subject: "biology", topic: "B2.1 Membranes and Membrane Transport", front: "What is osmosis?", back: "Net movement of water from a region of lower solute concentration to higher solute concentration through a selectively permeable membrane. Passive process." },
  { id: "fc-bi-B10", subject: "biology", topic: "B2.2 Organelles and Compartmentalization", front: "Why is compartmentalization important in eukaryotic cells?", back: "Allows different chemical environments for different reactions, increases efficiency, separates incompatible processes, concentrates enzymes and substrates." },
  { id: "fc-bi-B11", subject: "biology", topic: "B2.3 Cell Specialization", front: "What is the significance of the surface area to volume ratio?", back: "As cells grow, volume increases faster than surface area. Small cells have a larger SA:V ratio, allowing more efficient exchange of materials. This limits cell size." },
  { id: "fc-bi-B12", subject: "biology", topic: "B3.1 Gas Exchange", front: "What features make alveoli efficient for gas exchange?", back: "Large surface area, thin walls (one cell thick), dense capillary network, moist lining, ventilation maintains concentration gradient." },
  { id: "fc-bi-B13", subject: "biology", topic: "B3.2 Transport", front: "Compare arteries, veins, and capillaries.", back: "Arteries: thick muscular walls, small lumen, carry blood away from heart. Veins: thinner walls, larger lumen, valves, carry blood to heart. Capillaries: one cell thick, allow exchange." },
  { id: "fc-bi-B14", subject: "biology", topic: "B3.2 Transport", front: "Describe the cardiac cycle.", back: "Atrial systole (atria contract → blood to ventricles) → Ventricular systole (ventricles contract → blood to arteries) → Diastole (heart relaxes, fills with blood). Controlled by the SA node (pacemaker)." },
  { id: "fc-bi-B15", subject: "biology", topic: "B4.2 Ecological Niches", front: "What is the difference between a fundamental and realized niche?", back: "Fundamental niche: full range of conditions an organism could occupy. Realized niche: actual conditions it occupies due to competition and other interactions. Realized ⊂ Fundamental." },

  // BIOLOGY — Theme C: Interaction and Interdependence
  { id: "fc-bi-C1", subject: "biology", topic: "C1.1 Enzymes and Metabolism", front: "How do enzymes work (lock and key / induced fit)?", back: "Lock & key: substrate fits exactly into active site. Induced fit (more accurate): active site changes shape slightly upon substrate binding to form enzyme-substrate complex." },
  { id: "fc-bi-C2", subject: "biology", topic: "C1.1 Enzymes and Metabolism", front: "How does temperature affect enzyme activity?", back: "Increasing temp increases kinetic energy and reaction rate up to the optimum. Beyond optimum, hydrogen bonds break, active site denatures, activity drops to zero." },
  { id: "fc-bi-C3", subject: "biology", topic: "C1.1 Enzymes and Metabolism", front: "What is the difference between anabolic and catabolic reactions?", back: "Anabolic: build complex molecules from simpler ones (require energy), e.g., protein synthesis. Catabolic: break down complex molecules (release energy), e.g., cell respiration." },
  { id: "fc-bi-C4", subject: "biology", topic: "C1.2 Cell Respiration", front: "What is the overall equation for aerobic respiration?", back: "C₆H₁₂O₆ + 6O₂ → 6CO₂ + 6H₂O + energy (ATP). Glucose is oxidized, oxygen is reduced." },
  { id: "fc-bi-C5", subject: "biology", topic: "C1.2 Cell Respiration", front: "What is the role of ATP?", back: "ATP (adenosine triphosphate) is the universal energy currency of cells. Energy is released when the terminal phosphate bond is hydrolyzed (ATP → ADP + Pi)." },
  { id: "fc-bi-C6", subject: "biology", topic: "C1.2 Cell Respiration", front: "Compare lactic acid and ethanol fermentation.", back: "Lactic acid: in animals/some bacteria, pyruvate → lactate, reversible. Ethanol: in yeast/plants, pyruvate → ethanol + CO₂, irreversible. Both produce only 2 ATP per glucose." },
  { id: "fc-bi-C7", subject: "biology", topic: "C1.3 Photosynthesis", front: "What is the overall equation for photosynthesis?", back: "6CO₂ + 6H₂O → C₆H₁₂O₆ + 6O₂ (requires light energy). Carbon dioxide is reduced, water is oxidized." },
  { id: "fc-bi-C8", subject: "biology", topic: "C1.3 Photosynthesis", front: "What are the limiting factors of photosynthesis?", back: "Light intensity, CO₂ concentration, and temperature. At any time, the factor in shortest supply limits the rate (law of limiting factors)." },
  { id: "fc-bi-C9", subject: "biology", topic: "C2.2 Neural Signalling", front: "Describe the structure of a neuron.", back: "Cell body (with nucleus), dendrites (receive signals), axon (transmits impulse), myelin sheath (insulation, speeds up transmission), synaptic terminals (release neurotransmitters)." },
  { id: "fc-bi-C10", subject: "biology", topic: "C2.2 Neural Signalling", front: "What happens during synaptic transmission?", back: "Action potential arrives → Ca²⁺ enters terminal → vesicles fuse with membrane → neurotransmitter released into synaptic cleft → binds to receptors on postsynaptic membrane → signal continues or is inhibited." },
  { id: "fc-bi-C11", subject: "biology", topic: "C3.2 Defence Against Disease", front: "What are non-specific defences?", back: "Physical barriers (skin, mucous membranes), chemical barriers (stomach acid, lysozyme in tears), cellular (phagocytes engulf pathogens). They respond to ALL pathogens, no memory." },
  { id: "fc-bi-C12", subject: "biology", topic: "C3.2 Defence Against Disease", front: "How does the specific immune response work?", back: "B-lymphocytes produce antibodies (humoral). T-lymphocytes destroy infected cells (cell-mediated). Both are antigen-specific. Memory cells provide long-term immunity." },
  { id: "fc-bi-C13", subject: "biology", topic: "C3.2 Defence Against Disease", front: "How do antibiotics work and what is antibiotic resistance?", back: "Antibiotics kill bacteria or inhibit their growth (don't work on viruses). Overuse leads to natural selection of resistant bacteria. Resistant genes spread through populations." },
  { id: "fc-bi-C14", subject: "biology", topic: "C3.2 Defence Against Disease", front: "How do vaccines work?", back: "Contain weakened/dead pathogens or antigens. Stimulate immune response without causing disease. Memory cells form, providing faster/stronger response on future exposure." },
  { id: "fc-bi-C15", subject: "biology", topic: "C4.1 Populations and Communities", front: "What factors limit population growth?", back: "Density-dependent: competition, predation, disease, parasitism. Density-independent: natural disasters, climate. Carrying capacity (K) is the max population an environment can sustain." },
  { id: "fc-bi-C16", subject: "biology", topic: "C4.2 Transfers of Energy and Matter", front: "What is the 10% rule in energy transfer?", back: "Only ~10% of energy is transferred between trophic levels. ~90% is lost as heat through respiration, or in undigested material. This limits food chain length." },
  { id: "fc-bi-C17", subject: "biology", topic: "C4.2 Transfers of Energy and Matter", front: "Describe the carbon cycle.", back: "CO₂ absorbed by photosynthesis → organic compounds in producers → passed through food chains → returned by respiration, decomposition, and combustion of fossil fuels." },

  // BIOLOGY — Theme D: Continuity and Change
  { id: "fc-bi-D1", subject: "biology", topic: "D1.1 DNA Replication", front: "Describe semi-conservative DNA replication.", back: "Helicase unwinds and separates strands. DNA polymerase adds complementary nucleotides to each template strand. Each new molecule has one original and one new strand." },
  { id: "fc-bi-D2", subject: "biology", topic: "D1.1 DNA Replication", front: "What is PCR (polymerase chain reaction)?", back: "A technique to amplify small DNA samples. Cycles of: denaturation (95°C), annealing (55°C, primers bind), extension (72°C, Taq polymerase copies). Doubles DNA each cycle." },
  { id: "fc-bi-D3", subject: "biology", topic: "D1.1 DNA Replication", front: "What is gel electrophoresis?", back: "Separates DNA fragments by size. DNA (negative charge) moves through gel towards positive electrode. Smaller fragments move faster/further. Used in DNA profiling." },
  { id: "fc-bi-D4", subject: "biology", topic: "D1.2 Protein Synthesis", front: "Describe transcription.", back: "RNA polymerase binds to promoter on DNA → unwinds DNA → reads template strand 3'→5' → builds mRNA 5'→3' using complementary bases (U instead of T) → mRNA exits nucleus through nuclear pore." },
  { id: "fc-bi-D5", subject: "biology", topic: "D1.2 Protein Synthesis", front: "Describe translation.", back: "mRNA binds to ribosome → tRNA with complementary anticodon brings amino acid → codon-anticodon pairing → peptide bond forms between amino acids → ribosome moves along mRNA → polypeptide released at stop codon." },
  { id: "fc-bi-D6", subject: "biology", topic: "D1.2 Protein Synthesis", front: "What is meant by the genetic code being 'degenerate' and 'universal'?", back: "Degenerate: most amino acids are coded by more than one codon (64 codons for 20 amino acids). Universal: the same codons code for the same amino acids in virtually all organisms." },
  { id: "fc-bi-D7", subject: "biology", topic: "D1.3 Mutation and Gene Editing", front: "What are the types of gene mutations?", back: "Base substitution: one base replaced (may be silent, missense, or nonsense). Insertion: extra base added. Deletion: base removed. Insertions and deletions cause frameshift mutations." },
  { id: "fc-bi-D8", subject: "biology", topic: "D1.3 Mutation and Gene Editing", front: "What are mutagens?", back: "Agents that increase mutation rate. Chemical mutagens (e.g., benzene, tar), radiation (UV, X-rays, gamma rays), biological agents (some viruses). Mutations can be harmful, beneficial, or neutral." },
  { id: "fc-bi-D9", subject: "biology", topic: "D2.1 Cell and Nuclear Division", front: "What are the stages of mitosis?", back: "Prophase: chromosomes condense, nuclear envelope breaks. Metaphase: chromosomes align at equator. Anaphase: sister chromatids pulled apart. Telophase: nuclear envelopes reform. Cytokinesis: cell divides." },
  { id: "fc-bi-D10", subject: "biology", topic: "D2.1 Cell and Nuclear Division", front: "How does meiosis create genetic variation?", back: "Crossing over in prophase I (exchange of genetic material between homologous chromosomes). Independent assortment in metaphase I (random orientation of bivalents). Random fertilization adds further variation." },
  { id: "fc-bi-D11", subject: "biology", topic: "D2.1 Cell and Nuclear Division", front: "Compare mitosis and meiosis.", back: "Mitosis: 1 division, 2 identical diploid cells, growth/repair. Meiosis: 2 divisions, 4 genetically different haploid cells (gametes), creates genetic variation for sexual reproduction." },
  { id: "fc-bi-D12", subject: "biology", topic: "D2.3 Water Potential", front: "What happens to cells in hypertonic, hypotonic and isotonic solutions?", back: "Hypertonic: cell loses water (animal: crenation, plant: plasmolysis). Hypotonic: cell gains water (animal: lysis, plant: turgid). Isotonic: no net water movement." },
  { id: "fc-bi-D13", subject: "biology", topic: "D3.1 Reproduction", front: "Compare sexual and asexual reproduction.", back: "Sexual: two parents, meiosis + fertilization, genetically diverse offspring, slower. Asexual: one parent, mitosis only, genetically identical (clones), faster." },
  { id: "fc-bi-D14", subject: "biology", topic: "D3.2 Inheritance", front: "What is a monohybrid cross?", back: "A cross examining one gene with two alleles. Use a Punnett square. E.g., Aa × Aa gives 1 AA : 2 Aa : 1 aa genotypic ratio, 3:1 phenotypic ratio." },
  { id: "fc-bi-D15", subject: "biology", topic: "D3.2 Inheritance", front: "What is codominance?", back: "Both alleles are fully expressed in the heterozygote. Example: blood type — Iᴬ and Iᴮ are codominant, producing AB phenotype with both A and B antigens." },
  { id: "fc-bi-D16", subject: "biology", topic: "D3.2 Inheritance", front: "What is sex-linked inheritance?", back: "Genes on the X chromosome (e.g., color blindness, hemophilia). Males (XY) are more affected because they only need one recessive allele. Females can be carriers (heterozygous)." },
  { id: "fc-bi-D17", subject: "biology", topic: "D3.3 Homeostasis", front: "How is blood glucose regulated?", back: "High glucose → pancreas releases insulin → cells absorb glucose, liver stores glycogen → glucose drops. Low glucose → pancreas releases glucagon → liver breaks down glycogen → glucose rises. Negative feedback." },
  { id: "fc-bi-D18", subject: "biology", topic: "D3.3 Homeostasis", front: "What is negative feedback?", back: "A mechanism where a change in a variable triggers a response that reverses the change, returning the system to its set point. Examples: thermoregulation, blood glucose control." },
  { id: "fc-bi-D19", subject: "biology", topic: "D4.1 Natural Selection", front: "What conditions are needed for natural selection?", back: "Variation in a population (heritable traits), overproduction of offspring, competition for resources, differential survival and reproduction. Advantageous alleles increase in frequency." },
  { id: "fc-bi-D20", subject: "biology", topic: "D4.2 Stability and Change", front: "What is a keystone species?", back: "A species with a disproportionately large effect on its ecosystem relative to its abundance. Removal causes significant ecosystem change. Example: sea otters, wolves in Yellowstone." },
  { id: "fc-bi-D21", subject: "biology", topic: "D4.3 Climate Change", front: "What is the greenhouse effect?", back: "Solar radiation passes through atmosphere → Earth's surface absorbs and re-emits as infrared → greenhouse gases (CO₂, CH₄, N₂O, H₂O) trap heat → warms the planet. Enhanced by human activity." },
];

export function getFlashcardsBySubject(slug: string): Flashcard[] {
  return flashcards.filter(f => f.subject === slug);
}
